   281→void
   282→nfp_repr_transfer_features(struct net_device *netdev, struct net_device *lower)
   283→{
   284→	struct nfp_repr *repr = netdev_priv(netdev);
   285→
   286→	if (repr->dst->u.port_info.lower_dev != lower)
   287→		return;
   288→
   289→	netdev->gso_max_size = lower->gso_max_size;
   290→	netdev->gso_max_segs = lower->gso_max_segs;
   291→
   292→	netdev_update_features(netdev);
   293→}
