   295→static void nfp_repr_clean(struct nfp_repr *repr)
   296→{
   297→	unregister_netdev(repr->netdev);
   298→	nfp_app_repr_clean(repr->app, repr->netdev);
   299→	dst_release((struct dst_entry *)repr->dst);
   300→	nfp_port_free(repr->port);
   301→}
